import React, { useState } from 'react';
import './Login.css';

const Login = ({ setPage }) => {
  const [data, setData] = useState({ username: '', password: '' });

  const handleLogin = async (e) => {
    e.preventDefault();
    const response = await fetch('http://localhost:8000/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    const result = await response.json();
    alert(result.message);
  };

  return (
    <div className="login-box">
      <h2>GAMER LOGIN</h2>
      <form onSubmit={handleLogin}>
        <input type="text" placeholder="Username" required onChange={(e) => setData({...data, username: e.target.value})} />
        <input type="password" placeholder="Password" required onChange={(e) => setData({...data, password: e.target.value})} />
        <button type="submit">ENTER HUB</button>
      </form>
      <p className="switch-text" onClick={() => setPage('signup')}>New player? Register here.</p>
    </div>
  );
};

export default Login;
